-- Sync ratings for test users
UPDATE profiles p SET
  rating       = COALESCE((SELECT ROUND(AVG(r.rating)::numeric,1) FROM reviews r WHERE r.seller_id = p.id), 0),
  review_count = COALESCE((SELECT COUNT(*)                        FROM reviews r WHERE r.seller_id = p.id), 0)
WHERE p.username LIKE 'test_%';

